import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v5 ===');
w('profiles_v5','volkswagen-group',{"brand_name":"Volkswagen Group","brand_slug":"volkswagen-group","parent_company":"Volkswagen AG","ultimate_parent":"Volkswagen AG","overall_concern_level":"significant","profile_type":"database","generated_headline":"VOLKSWAGEN INSTALLED SOFTWARE TO CHEAT EMISSIONS TESTS IN 11 MILLION VEHICLES — THEIR OWN CEO RESIGNED AND SIX EXECUTIVES WERE CONVICTED","executive_summary":"Volkswagen AG is the world's largest automaker. In September 2015, the US EPA revealed that Volkswagen had installed defeat device software in approximately 11 million diesel vehicles — software that detected emissions testing and reduced NOx only during tests, while emitting up to 40 times the legal NOx limit during real-world driving. CEO Martin Winterkorn resigned within days. VW pleaded guilty to US criminal charges in 2017 and paid $4.3 billion — the largest criminal penalty ever assessed against an automaker. Total global settlements exceeded $30 billion. Six VW executives were convicted in German courts.","verdict_tags":["defeat_device_11_million_vehicles","4_3b_us_criminal_penalty_largest_automaker","30b_global_settlements","ceo_resigned","six_executives_convicted_germany","nox_40x_legal_limit"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"30,000 job cuts as VW restructured to fund $30 billion in settlements.","flags":["30000_job_cuts_scandal_restructuring"],"sources":[]},"environmental":{"summary":"NOx emissions from 11 million defeat-device vehicles exceeded legal limits by up to 40 times during real-world driving. A study estimated the excess NOx caused approximately 59 premature deaths in the United States and 1,200 new cases of asthma.","flags":["40x_nox_legal_limit_real_world","59_estimated_us_premature_deaths"],"sources":["https://ehp.niehs.nih.gov/doi/10.1289/EHP1875"]},"political":{"summary":"VW lobbied against stricter real-world emissions testing standards in the years before the defeat device was discovered. EU regulatory reform followed the scandal.","flags":["vw_lobbied_against_stricter_testing_pre_scandal"],"sources":[]},"legal":{"summary":"January 2017: VW AG pleaded guilty to three US criminal charges. Criminal penalty: $2.8 billion. Civil penalty: $1.5 billion. Consumer settlement: $14.7 billion. Six VW executives convicted in Germany. Rupert Stadler convicted 2023.","flags":["4_3b_largest_automaker_criminal_penalty","14_7b_us_consumer_settlement","six_executives_convicted_germany"],"sources":["https://www.justice.gov/opa/pr/volkswagen-ag-agrees-plead-guilty-and-pay-43-billion-criminal-and-civil-penalties-six"]},"tax":{"summary":"The $30 billion in settlements generated tax deductions reducing the net penalty cost to VW shareholders.","flags":["settlement_provision_tax_deduction_global"],"sources":[]},"executives":{"summary":"CEO Martin Winterkorn resigned September 23, 2015 and was subsequently charged with fraud by German prosecutors. Rupert Stadler convicted 2023. James Liang sentenced to 40 months in the US.","flags":["winterkorn_criminal_charges_germany","stadler_convicted_suspended_sentence","liang_40_months_us_imprisonment"],"sources":[]},"connections":{"summary":"VW's defeat device relied on engine management software supplied by Bosch — which separately settled US claims for $327.5 million. The Piëch and Porsche family ownership gives founding families voting control insulating the company from shareholder accountability.","flags":["bosch_supplier_settled_separately","piech_porsche_family_voting_control"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"German prosecutors alleged Winterkorn was briefed on the defeat device as early as May 2014 — over a year before public disclosure.","flags":["winterkorn_2014_briefing_alleged"],"sources":[]},"health_record":{"summary":"Study estimated 59 premature US deaths and 1,200 asthma cases from excess NOx. European estimates exceed 1,000 premature deaths. Communities near highways absorbed the highest exposure.","flags":["59_us_premature_deaths_estimated"],"sources":[]},"alternatives":{"cheaper":["Toyota hybrids — consistently lowest total cost of ownership without diesel complexity"],"healthier":["Battery electric vehicles eliminate diesel NOx entirely"],"diy":["Check your VW diesel VIN at the EPA VW settlement website for extended warranty coverage"]},"timeline":[{"year":2006,"event":"Defeat device software development begins","severity":"critical","source_url":""},{"year":2015,"event":"September 18: EPA issues notice of violation. September 23: CEO Winterkorn resigns.","severity":"critical","source_url":"https://www.epa.gov/vw"},{"year":2017,"event":"$4.3B US criminal + civil penalty. James Liang sentenced to 40 months.","severity":"critical","source_url":"https://www.justice.gov/opa/pr/volkswagen-ag-agrees-plead-guilty-and-pay-43-billion-criminal-and-civil-penalties-six"},{"year":2023,"event":"Former Audi CEO Rupert Stadler convicted in Germany","severity":"high","source_url":""}],"community_impact":{"displacement":"Communities near highways absorbed elevated NOx from 11 million non-compliant vehicles for years without knowledge or consent.","price_illusion":"VW diesel vehicles were marketed with 'TDI Clean Diesel' branding commanding a premium for environmental performance that did not exist.","tax_math":"The $30 billion in global settlements generated tax deductions reducing the net penalty cost to VW shareholders.","wealth_velocity":"Volkswagen is controlled by the Piëch and Porsche families through Porsche Automobil Holding SE."},"cost_absorption":{"who_benefited":[{"group":"Volkswagen shareholders and Piëch/Porsche families","how":"Eight years of diesel sales at premium TDI pricing without the cost of actual NOx reduction technology"}],"who_paid":[{"group":"Communities near highways","how":"Excess NOx exposure for eight years; 59 estimated US premature deaths"},{"group":"VW diesel owners","how":"Premium price for environmental performance that did not exist"}],"the_gap":"Volkswagen installed software in 11 million vehicles specifically designed to cheat on emissions tests. The vehicles emitted 40 times the legal limit when nobody was measuring. The CEO resigned. Six executives were convicted. The company paid $30 billion. The engineer who built it served 40 months. The communities near the highways where those vehicles drove absorbed the emissions for eight years."}});
w('profiles_v5','hsbc',{"brand_name":"HSBC","brand_slug":"hsbc","parent_company":"HSBC Holdings plc","ultimate_parent":"HSBC Holdings plc","overall_concern_level":"significant","profile_type":"database","generated_headline":"HSBC PROCESSED HUNDREDS OF MILLIONS FOR THE SINALOA CARTEL AND PAID $1.9 BILLION — NOT ONE EXECUTIVE WAS CRIMINALLY CHARGED","executive_summary":"HSBC Holdings plc is Europe's largest bank by assets. In December 2012, HSBC entered into a Deferred Prosecution Agreement and agreed to pay $1.9 billion — the largest bank money laundering settlement in history at the time — for systematically failing to maintain adequate anti-money laundering controls. HSBC's Mexican subsidiary moved at least $881 million for the Sinaloa Cartel through accounts cartel money launderers called 'drug accounts.' HSBC also violated US sanctions against Iran, Sudan, Libya, Cuba, and Burma. No HSBC executive was criminally charged. The bank was described by US Senate investigators as having a 'pervasively polluted' culture of compliance failure.","verdict_tags":["1_9b_money_laundering_settlement_largest_at_time","sinaloa_cartel_881m_documented","iran_sudan_libya_cuba_sanctions_violations","no_executive_criminally_charged","senate_pervasively_polluted_finding"],"concern_flags":{"labor":false,"environmental":true,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"HSBC employs approximately 220,000 people globally. Multiple rounds of significant workforce reductions have occurred. No major systematic labor violations comparable to its money laundering record.","flags":[],"sources":[]},"environmental":{"summary":"HSBC is among the largest financiers of fossil fuel expansion globally. A 2021 internal HSBC presentation leaked by a whistleblower showed an executive dismissing climate risks as 'blah blah blah.' The bank subsequently suspended that executive.","flags":["major_fossil_fuel_financier_europe","internal_climate_dismissal_documented_leaked"],"sources":[]},"political":{"summary":"The 2012 DPA — rather than a criminal indictment — was justified partly by citing risk that a criminal conviction could destabilize a major global financial institution. This rationale was explicitly criticized as establishing a 'too big to jail' doctrine for major banks.","flags":["too_big_to_jail_doctrine_dpa_not_criminal"],"sources":[]},"legal":{"summary":"December 2012: HSBC agreed to pay $1.9 billion and enter a five-year DPA. The settlement covered $881 million in cartel laundering; stripping information from wire transfers to evade OFAC sanctions; failing to monitor over $670 billion in wire transfers. In 2021, UK FCA fined HSBC £63.9M for AML failings.","flags":["1_9b_dpa_largest_aml_at_time","881m_cartel_laundering","670b_wire_transfers_unmonitored","fca_2021_subsequent_failings"],"sources":["https://www.justice.gov/opa/pr/hsbc-holdings-plc-and-hsbc-bank-usa-na-admit-anti-money-laundering-and-sanctions-violations"]},"tax":{"summary":"HSBC's Swiss private banking subsidiary was at the center of the 'SwissLeaks' scandal in 2015 — holding accounts for approximately 30,000 clients helping them evade taxes. France fined HSBC €300 million for tax fraud assistance.","flags":["swissleaks_30000_clients_tax_evasion","france_300m_tax_fraud_fine"],"sources":[]},"executives":{"summary":"No HSBC executive was criminally charged in the 2012 US settlement. Former Group CEO Stuart Gulliver's personal tax arrangements — revealed in SwissLeaks — showed he had routed compensation through a Panamanian company held in the same HSBC Switzerland subsidiary helping clients evade taxes.","flags":["no_executive_criminal_charges_1_9b_settlement","gulliver_personal_offshore_swissleaks"],"sources":[]},"connections":{"summary":"The 'too big to jail' precedent HSBC established was extended to other major banks in subsequent AML settlements. The bank's simultaneous presence in virtually every major financial market makes it systemically important — a characteristic the DOJ explicitly cited in justifying a DPA rather than criminal prosecution.","flags":["too_big_to_jail_precedent_extended_industry"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The US Senate Permanent Subcommittee's 2012 report alleged HSBC executives were aware of the money laundering risks presented by their Mexican affiliate and did not act — in some cases allegedly overriding compliance officers' concerns.","flags":["executive_awareness_alleged_senate_report","compliance_officers_overridden_alleged"],"sources":[]},"health_record":{"summary":"HSBC's facilitation of cartel money laundering directly financed the Sinaloa Cartel — organizations responsible for producing and distributing fentanyl, heroin, methamphetamine, and cocaine into US communities. The bank received fee income on every transaction it processed for cartel accounts.","flags":["cartel_financing_opioid_crisis_connection","fee_income_on_cartel_transactions"],"sources":[]},"alternatives":{"cheaper":["Credit unions — member-owned, not-for-profit financial institutions with documented better rates","Local community banks — deposit insurance same as HSBC; profits stay in community"],"healthier":["Credit unions — documented better customer outcomes, lower fees, no systemic money laundering settlements"],"diy":["Check if your bank has DOJ enforcement history at violationtracker.goodjobsfirst.org","Credit union finder at MyCreditUnion.gov"]},"timeline":[{"year":2012,"event":"July: US Senate report documents 'pervasively polluted' HSBC compliance culture. December: $1.9B DPA — no criminal charges, no executive indicted.","severity":"critical","source_url":"https://www.justice.gov/opa/pr/hsbc-holdings-plc-and-hsbc-bank-usa-na-admit-anti-money-laundering-and-sanctions-violations"},{"year":2015,"event":"SwissLeaks: ICIJ publishes data showing HSBC Switzerland held 30,000 client accounts for tax evasion","severity":"critical","source_url":""},{"year":2021,"event":"UK FCA fines HSBC £63.9M for AML failings — 9 years after the US settlement","severity":"high","source_url":""}],"community_impact":{"displacement":"The Sinaloa Cartel's operational financing — facilitated through HSBC Mexico — funded the infrastructure of a criminal organization that devastated communities through violence, drug distribution, and corruption.","price_illusion":"HSBC presents itself as a global banking institution with standards appropriate to its scale. The Senate investigation found it had 'pervasively polluted' compliance culture where accounts known internally as 'drug accounts' processed cartel funds.","tax_math":"The SwissLeaks showed HSBC Switzerland actively helping clients evade taxes in 60+ countries. The tax revenue lost represents public funds.","wealth_velocity":"Revenue from fee income on cartel transactions, from helping wealthy clients evade taxes, and from processing sanctions violations flowed to London and to institutional shareholders globally."},"cost_absorption":{"who_benefited":[{"group":"HSBC shareholders","how":"Fee income from cartel accounts, sanctions violations, and tax evasion facilitation; DPA avoided criminal conviction"},{"group":"Sinaloa Cartel","how":"$881M laundered through HSBC Mexico accounts; operational funding for drug trafficking and violence"}],"who_paid":[{"group":"Communities affected by Sinaloa Cartel operations","how":"Violence, drug distribution, institutional corruption funded by laundered cartel proceeds"},{"group":"Taxpayers in 60+ countries","how":"Tax revenue lost through HSBC-facilitated evasion at Swiss private banking subsidiary"}],"the_gap":"HSBC processed $881 million for the Sinaloa Cartel through accounts cartel money launderers called 'drug accounts.' The US Senate said the compliance culture was 'pervasively polluted.' HSBC paid $1.9 billion and signed a deferred prosecution agreement. No executive was criminally charged. Five years later the DPA expired. The same year, the UK fined HSBC again for AML failings."}});
w('profiles_v5','deutsche-bank',{"brand_name":"Deutsche Bank","brand_slug":"deutsche-bank","parent_company":"Deutsche Bank AG","ultimate_parent":"Deutsche Bank AG","overall_concern_level":"significant","profile_type":"database","generated_headline":"DEUTSCHE BANK BANKED JEFFREY EPSTEIN FOR 18 YEARS AFTER HIS 2008 CONVICTION AND PAID $150M — THAT WAS THE SMALLEST OF ITS FOUR MAJOR SETTLEMENTS THIS DECADE","executive_summary":"Deutsche Bank AG is Germany's largest bank. Between 2013 and 2018, Deutsche Bank maintained accounts for Jeffrey Epstein — a registered sex offender since his 2008 Florida conviction — processing approximately $120 million in transactions and noting 'reputational risks' in internal documents while continuing the relationship. New York's DFS fined Deutsche Bank $150 million in 2020. This was Deutsche Bank's smallest major settlement in recent years: the bank also paid $7.2 billion for mortgage-backed securities fraud (2017), $2.5 billion for LIBOR manipulation (2015), and $630 million for a Russian mirror trading scheme that laundered approximately $10 billion.","verdict_tags":["epstein_banking_18_years_post_conviction","150m_dfs_epstein_fine","7_2b_mortgage_securities_settlement","2_5b_libor_manipulation","630m_russian_mirror_trading","four_major_settlements_one_decade"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Deutsche Bank has reduced its workforce from approximately 100,000 to 85,000 through restructuring programs driven by the need to rebuild capital after multiple massive settlements.","flags":[],"sources":[]},"environmental":{"summary":"Deutsche Bank's DWS asset management subsidiary — the SEC fined DWS $19 million for making materially misleading statements about its ESG integration in investment processes.","flags":["dws_19m_sec_greenwashing_fine"],"sources":["https://www.sec.gov/news/press-release/2023-86"]},"political":{"summary":"Deutsche Bank was Donald Trump's primary lender for approximately two decades — extending over $2 billion in loans when other major banks had cut ties. The bank's own anti-financial crime staff had flagged suspicious transactions in Trump and Kushner accounts and were reportedly overruled by senior management.","flags":["trump_primary_lender_2_billion","trump_kushner_aml_flags_overruled_nyt_report"],"sources":[]},"legal":{"summary":"2015: $2.5B LIBOR settlement; Deutsche Bank entity pleads guilty to wire fraud. 2017: $7.2B DOJ settlement for mortgage-backed securities fraud. 2017: $630M settlement for Russian mirror trading scheme — approximately $10B in suspicious transactions. 2020: $150M DFS fine for Epstein AML failings. Total US settlements exceed $10.5B.","flags":["2_5b_libor_criminal_guilty_plea","7_2b_mortgage_securities","630m_russian_mirror_trading","150m_epstein_aml","10_5b_total_decade"],"sources":["https://www.justice.gov/opa/pr/deutsche-bank-agrees-pay-72-billion-misconduct-relating-mortgage-backed-securities"]},"tax":{"summary":"Deutsche Bank was investigated by German tax authorities in 2012 over a €900 million VAT fraud scheme involving carbon emissions trading certificates — German police raided Frankfurt HQ. The bank paid €202 million to resolve the investigation.","flags":["900m_vat_fraud_carbon_trading_investigation"],"sources":[]},"executives":{"summary":"Deutsche Bank has had five CEOs in ten years. No Deutsche Bank executive was criminally charged in any of the four major US settlements. The LIBOR guilty plea was at the entity level.","flags":["five_ceos_ten_years","no_executive_criminal_charges"],"sources":[]},"connections":{"summary":"Deutsche Bank's Russian mirror trading scheme operated through three branches simultaneously. Approximately $10 billion was moved. The Russian clients have not been publicly identified.","flags":["russian_mirror_trading_three_branch_simultaneous","clients_identities_not_public"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The New York Times reported in 2020 that Deutsche Bank's anti-financial crime staff had flagged transactions in Trump and Kushner accounts as potentially suspicious and recommended filing Suspicious Activity Reports — and that senior management overruled these recommendations. Deutsche Bank denied this.","flags":["trump_kushner_sar_recommendations_overruled_alleged_nyt"],"sources":[]},"health_record":{"summary":"Deutsche Bank's banking of Jeffrey Epstein provided the financial infrastructure for his continued activities between 2013 and 2018. The DFS order documented that Deutsche Bank processed payments to Epstein's alleged co-conspirators and women identified as victims. The bank's own documents noted reputational risks and proceeded anyway.","flags":["epstein_financial_infrastructure_2013_2018","payments_to_alleged_coconspirators_documented"],"sources":["https://www.dfs.ny.gov/reports_and_publications/press_releases/pr202007072"]},"alternatives":{"cheaper":["Credit unions for personal banking — no serial AML settlement history"],"healthier":["Deutsche Bank's DWS greenwashing settlement means ESG funds branded as 'sustainable' were not — verify any DWS fund's actual holdings"],"diy":["Violation Tracker at goodjobsfirst.org shows complete settlement history for any bank"]},"timeline":[{"year":2013,"event":"Deutsche Bank begins banking Jeffrey Epstein despite his 2008 sex offense conviction — internal documents note 'reputational risks'","severity":"critical","source_url":""},{"year":2015,"event":"$2.5B LIBOR settlement; entity pleads guilty to wire fraud; no individual charged","severity":"critical","source_url":""},{"year":2017,"event":"$7.2B DOJ settlement for toxic mortgage-backed securities. $630M settlement for Russian mirror trading.","severity":"critical","source_url":""},{"year":2020,"event":"July: NY DFS $150M fine for Epstein AML failings","severity":"high","source_url":"https://www.dfs.ny.gov/reports_and_publications/press_releases/pr202007072"},{"year":2023,"event":"SEC fines DWS $19M for greenwashing","severity":"high","source_url":""}],"community_impact":{"displacement":"The LIBOR manipulation affected trillions of dollars in financial contracts globally. Municipalities, pension funds, and ordinary borrowers with LIBOR-linked loans were overcharged. The Russian mirror trading scheme moved approximately $10 billion of potentially suspicious money.","price_illusion":"Deutsche Bank's DWS funds were sold to investors as sustainable ESG investments. The SEC found those claims were materially misleading. Deutsche Bank's mortgage securities were sold as investment-grade products the bank knew were backed by defective loans.","tax_math":"The €900 million carbon trading VAT fraud scheme involved Deutsche Bank clients using the bank's infrastructure to fraudulently claim VAT refunds — stealing from European governments' tax revenues.","wealth_velocity":"Deutsche Bank is publicly traded on the Frankfurt Stock Exchange. Revenue from the Russian mirror trading, LIBOR manipulation, and mortgage securities fraud flowed to shareholders during those periods."},"cost_absorption":{"who_benefited":[{"group":"Deutsche Bank shareholders","how":"Revenue from LIBOR manipulation, toxic mortgage securities, Russian mirror trading, and Epstein banking relationship"},{"group":"Epstein","how":"Banking infrastructure after his 2008 conviction; approximately $120M in transactions processed"}],"who_paid":[{"group":"Municipalities and pension funds with LIBOR-linked contracts","how":"Overcharged on interest rates by manipulated LIBOR benchmark"},{"group":"Epstein's victims 2013-2018","how":"Banking infrastructure provided to Epstein after conviction continued financing his activities"}],"the_gap":"Deutsche Bank banked Jeffrey Epstein from 2013 to 2018 — five years after he was a convicted sex offender. Their own documents said it was a reputational risk. They kept the account. They paid $150 million for it. That was their smallest settlement. The LIBOR fine was $2.5 billion. The mortgage fraud was $7.2 billion. The Russian mirror trading was $630 million. No executive was criminally charged for any of it."}});
w('profiles_v5','airbnb',{"brand_name":"Airbnb","brand_slug":"airbnb","parent_company":"Airbnb, Inc.","ultimate_parent":"Airbnb, Inc.","overall_concern_level":"moderate","profile_type":"database","generated_headline":"HARVARD RESEARCHERS FOUND AIRBNB HOSTS 16% LESS LIKELY TO ACCEPT BLACK GUESTS — AIRBNB'S OWN AUDIT CONFIRMED IT AND THEY CALLED THE PROBLEM 'PROJECT LIGHTHOUSE'","executive_summary":"Airbnb, Inc. operates a global short-term rental platform with over 7 million active listings. A 2016 Harvard Business School study documented that guests with distinctively African American names were 16% less likely to be accepted by Airbnb hosts. Airbnb commissioned its own internal audit ('Project Lighthouse') which confirmed the discrimination problem. Housing researchers have documented significant reductions in residential housing stock in cities including Barcelona, Amsterdam, New York, and San Francisco. Airbnb and Uber together spent $220 million on California's Proposition 22 and has lobbied against local short-term rental regulations across dozens of cities globally.","verdict_tags":["16pct_racial_discrimination_harvard_documented","project_lighthouse_airbnb_confirmed_own_audit","housing_stock_reduction_documented_multiple_cities","local_regulation_lobbying_circumvention"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Airbnb's platform model classifies hosts as independent contractors who bear all operational risk. New York registration data showed the majority of nights booked were through professional multi-listing hosts operating commercial operations.","flags":["host_operational_risk_bearing","professional_host_majority_documented_new_york"],"sources":[]},"environmental":{"summary":"Studies have documented that Airbnb increases vehicle miles traveled by reducing transit ridership. Short-term rental guests typically have higher per-stay energy and water consumption than long-term residents.","flags":["housing_density_reduction_environmental_effect"],"sources":[]},"political":{"summary":"Airbnb sued to block New York City's Local Law 18 which required host registration. The lawsuit failed. In Barcelona, Amsterdam, and Paris, Airbnb has repeatedly faced regulatory action for facilitating unregistered listings violating local housing law.","flags":["local_law_18_new_york_litigation_failed","barcelona_amsterdam_paris_regulatory_action"],"sources":[]},"legal":{"summary":"The 2016 Harvard discrimination study led to an FTC investigation. Airbnb settled a 2016 class action alleging racial discrimination, creating its 'Project Lighthouse' internal audit that confirmed the discrimination problem. New York's enforcement of Local Law 18 removed approximately 15,000 listings.","flags":["harvard_discrimination_class_action_settlement","project_lighthouse_discrimination_confirmed","new_york_15000_listings_removed"],"sources":["https://hbswk.hbs.edu/item/racial-discrimination-in-the-sharing-economy-evidence-from-a-field-experiment"]},"tax":{"summary":"Airbnb has faced tax disputes with multiple jurisdictions over its responsibility to collect and remit local occupancy taxes. Many Airbnb hosts fail to report rental income.","flags":["occupancy_tax_collection_disputes","host_income_tax_reporting_compliance_gap"],"sources":[]},"executives":{"summary":"CEO Brian Chesky co-founded Airbnb in 2008 and led it through its December 2020 IPO at approximately $47 billion valuation — on a platform that had confirmed racial discrimination in its acceptance rates through its own Project Lighthouse audit.","flags":["10b_ipo_wealth_on_platform_with_confirmed_discrimination"],"sources":[]},"connections":{"summary":"Academic research in cities including Barcelona, New York, and Amsterdam has documented relationships between Airbnb density and rental price increases in surrounding neighborhoods. Airbnb has consistently disputed the magnitude of these effects while the academic consensus has grown stronger.","flags":["housing_financialization_connection","academic_consensus_price_effect_growing"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Housing researchers have alleged that Airbnb's lobbying characterizes its platform as primarily 'home sharing' by individual homeowners — when New York registration data showed the majority of nights booked were through multi-listing professional hosts operating commercial operations.","flags":["commercial_host_majority_home_sharing_framing_alleged"],"sources":[]},"health_record":{"summary":"Airbnb listings are not subject to the same health and safety inspections as licensed hotels. The platform has faced significant liability claims for deaths and injuries in unlicensed properties — carbon monoxide poisoning, structural failures, and fires.","flags":["no_government_safety_inspection_hotel_parity_gap"],"sources":[]},"alternatives":{"cheaper":["Traditional hotels — price-competitive in most markets when Airbnb cleaning fees and service fees are included in total cost"],"healthier":["Government-inspected hotels — fire safety, smoke alarms, CO detectors verified by local authorities"],"diy":["Calculate full Airbnb cost including cleaning fee, service fee, and taxes before comparing to hotel","Check your city's short-term rental registration list — stay only in registered listings"]},"timeline":[{"year":2016,"event":"Harvard Business School study documents 16% lower acceptance rate for Black guests; Project Lighthouse confirms discrimination","severity":"critical","source_url":"https://hbswk.hbs.edu/item/racial-discrimination-in-the-sharing-economy-evidence-from-a-field-experiment"},{"year":2020,"event":"December: Airbnb IPO at $47B valuation","severity":"neutral","source_url":""},{"year":2023,"event":"New York City Local Law 18 takes effect; Airbnb loses lawsuit; approximately 15,000 listings removed","severity":"critical","source_url":""},{"year":2024,"event":"Barcelona announces ban on tourist apartment renewals citing housing crisis","severity":"high","source_url":""}],"community_impact":{"displacement":"Academic research across dozens of cities has documented that increased Airbnb density is associated with higher rental prices and reduced housing availability for long-term residents.","price_illusion":"Airbnb's pricing display — showing low per-night base prices before adding cleaning fees, service fees, and occupancy taxes — has been documented to systematically inflate the apparent price advantage over hotels.","tax_math":"Short-term rental income earned by Airbnb hosts is taxable income that many hosts do not report.","wealth_velocity":"Airbnb's market capitalization concentrates in its three founders and institutional investors. Housing units converted to short-term rentals redirect community real estate from long-term use to short-term visitor revenue, with platform fees flowing to San Francisco."},"cost_absorption":{"who_benefited":[{"group":"Airbnb founders and investors","how":"$10B+ each at IPO from platform whose discrimination problem was confirmed in their own internal audit"},{"group":"Professional multi-listing hosts","how":"Commercial real estate operators using 'home sharing' framing to operate hotel-equivalent businesses without hotel regulations"}],"who_paid":[{"group":"Black guests discriminated against","how":"16% lower acceptance rate documented; denied accommodation based on names associated with racial identity"},{"group":"Long-term residents in high-Airbnb neighborhoods","how":"Documented rental price increases and reduced availability as residential units convert to short-term rental use"}],"the_gap":"Airbnb commissioned an audit called Project Lighthouse. It confirmed their platform discriminates against Black guests. The platform's mechanism — individual host discretion on accepting guests — is still the mechanism. The company went public at $47 billion. The founders became billionaires. The neighborhoods where Airbnb is densest have documented higher rents. The Black guests are 16% less likely to get the room."}});
w('profiles_v5','cencora',{"brand_name":"Cencora","brand_slug":"cencora","parent_company":"Cencora, Inc.","ultimate_parent":"Cencora, Inc.","overall_concern_level":"significant","profile_type":"database","generated_headline":"AMERISOURCEBERGEN — NOW CENCORA — DISTRIBUTED BILLIONS OF OPIOID PILLS AND PAID $6.1 BILLION. THE REBRAND DID NOT CHANGE THE UNDERLYING BUSINESS.","executive_summary":"Cencora, Inc. is one of the three dominant US pharmaceutical distributors — formerly known as AmerisourceBergen until a 2023 rebrand. Together with McKesson and Cardinal Health, Cencora controls approximately 85-90% of US drug distribution. As part of the $21 billion three-distributor opioid settlement reached in 2022, Cencora agreed to pay $6.1 billion over 18 years. Like McKesson and Cardinal Health, Cencora distributed billions of opioid pills to pharmacies while allegedly failing to implement the anti-diversion controls required by the Controlled Substances Act. The company rebranded from AmerisourceBergen to Cencora in 2023.","verdict_tags":["6_1b_opioid_settlement_21b_three_distributor","opioid_distribution_billions_of_pills","anti_diversion_failure_documented","rebrand_amerisourcebergen_to_cencora_2023","distribution_oligopoly_85_90pct"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Cencora employs approximately 46,000 people globally. No major documented systemic labor violations have been identified as a primary concern.","flags":[],"sources":[]},"environmental":{"summary":"Pharmaceutical distribution involves cold-chain logistics with significant refrigeration and transportation energy consumption. No major environmental enforcement actions have been identified.","flags":[],"sources":[]},"political":{"summary":"Cencora and its distributor peers lobbied against the HALT Act — legislation that would have strengthened the DEA's authority to suspend distributors' licenses. A Washington Post and 60 Minutes investigation documented how the drug distribution industry worked to weaken DEA enforcement authority.","flags":["halt_act_opposition_dea_authority_weakening","washington_post_60_minutes_investigation"],"sources":["https://www.washingtonpost.com/investigations/the-drug-industrys-triumph-over-the-dea/2017/10/15/"]},"legal":{"summary":"In 2022, AmerisourceBergen (now Cencora) agreed to pay $6.1 billion over 18 years as part of the three-distributor $21 billion opioid settlement — the largest pharmaceutical settlement in US history. The settlement resolves claims that AmerisourceBergen failed to detect, investigate, and report suspicious opioid orders. The company has never admitted wrongdoing.","flags":["6_1b_opioid_settlement_18_years","no_admission_wrongdoing"],"sources":["https://www.justice.gov/opa/pr/justice-department-announces-global-resolution-opioid-lawsuits-against-three-largest-us"]},"tax":{"summary":"Cencora's $6.1 billion settlement payments are spread over 18 years and may be partially tax-deductible — effectively requiring US taxpayers to subsidize a portion of the opioid distribution penalty.","flags":["settlement_18_year_payment_schedule","potential_deductibility_taxpayer_subsidy"],"sources":[]},"executives":{"summary":"CEO Steven Collis has led Cencora through the opioid settlement and rebrand. No Cencora executive has been criminally charged. The rebrand from AmerisourceBergen to Cencora in August 2023 was publicly explained as reflecting global growth.","flags":["no_executive_criminal_charges","rebrand_timing_post_settlement"],"sources":[]},"connections":{"summary":"Cencora, McKesson, and Cardinal Health together control 85-90% of US drug distribution — a concentrated oligopoly. All three are defendants in the $21 billion opioid settlement. All three lobbied against stronger DEA oversight. The structure that allowed the opioid crisis remains intact.","flags":["three_distributor_oligopoly_intact_post_settlement","all_three_lobbied_dea_oversight"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"State attorneys general have alleged that AmerisourceBergen was aware of the suspicious opioid order patterns its own system was generating and chose not to report them to the DEA — prioritizing distribution volume over compliance obligations.","flags":["suspicious_order_awareness_no_dea_reporting_alleged"],"sources":[]},"health_record":{"summary":"The opioid crisis killed approximately 500,000 Americans from prescription opioid, heroin, and synthetic opioid overdoses between 1999 and 2019. Cencora's distribution of billions of opioid pills without the anti-diversion controls the Controlled Substances Act required contributed directly to this catastrophe.","flags":["500000_overdose_deaths_opioid_crisis","anti_diversion_failure_contributed_deaths"],"sources":[]},"alternatives":{"cheaper":["Drug distribution is B2B infrastructure. The reform alternative is mandatory anti-diversion reporting with real enforcement consequences."],"healthier":["Non-opioid pain management: physical therapy, regional anesthesia, NSAIDs, CBT for chronic pain","SAMHSA National Helpline: 1-800-662-4357 for substance use disorder treatment referral"],"diy":["Support harm reduction: naloxone distribution, needle exchanges, medication-assisted treatment programs"]},"timeline":[{"year":2017,"event":"Washington Post / 60 Minutes investigation documents drug industry lobbying against DEA enforcement","severity":"critical","source_url":"https://www.washingtonpost.com/investigations/the-drug-industrys-triumph-over-the-dea/2017/10/15/"},{"year":2022,"event":"$21B three-distributor opioid settlement; AmerisourceBergen's share: $6.1B over 18 years; no admission of wrongdoing","severity":"critical","source_url":""},{"year":2023,"event":"AmerisourceBergen rebrands to Cencora","severity":"moderate","source_url":""}],"community_impact":{"displacement":"West Virginia communities experienced workforce destruction, family dissolution, and increased foster care placements from the opioid crisis.","price_illusion":"Pharmaceutical distribution appears to be invisible infrastructure. The economics are direct: distributors earn a per-pill margin on every opioid they ship. Anti-diversion controls that would have reduced suspicious orders would have directly reduced revenue.","tax_math":"The $6.1 billion settlement is spread over 18 years and may be partially tax-deductible. The public healthcare costs of opioid addiction substantially exceed the settlement amount.","wealth_velocity":"Cencora's revenue — approximately $238 billion annually — flows to institutional shareholders. The settlement is paid from future earnings generated by the same distribution business."},"cost_absorption":{"who_benefited":[{"group":"Cencora/AmerisourceBergen shareholders","how":"Per-pill revenue from distributing billions of opioids; settlement paid over 18 years; rebrand separates current name from conduct history"}],"who_paid":[{"group":"Approximately 500,000 Americans who died of opioid overdoses","how":"Prescription pill saturation of communities directly connected to distribution volumes"},{"group":"Appalachian and rural communities","how":"Disproportionate per-capita pill volumes; highest overdose death rates; generational economic destruction"}],"the_gap":"AmerisourceBergen distributed billions of opioid pills. The Washington Post documented that they lobbied against the regulations that would have required them to report suspicious orders. They paid $6.1 billion. No executive was criminally charged. They renamed the company Cencora. The settlement is paid over 18 years. The opioid crisis killed 500,000 people."}});
w('profiles_v5','fresenius-medical-care',{"brand_name":"Fresenius Medical Care","brand_slug":"fresenius-medical-care","parent_company":"Fresenius Medical Care AG","ultimate_parent":"Fresenius SE & Co. KGaA","overall_concern_level":"significant","profile_type":"database","generated_headline":"FRESENIUS CONTROLS 35% OF US DIALYSIS ALONGSIDE DAVITA AND PAID $231 MILLION FOR BILLING PATIENTS FOR TREATMENTS THEY DID NOT NEED","executive_summary":"Fresenius Medical Care is the world's largest provider of kidney dialysis services, operating approximately 4,000 dialysis clinics in the United States — approximately 35% of the US market. Together with DaVita (approximately 35%), Fresenius operates a near-duopoly over dialysis — a life-sustaining treatment patients cannot miss. In 2019, Fresenius agreed to pay $231 million to resolve DOJ allegations that it provided medically unnecessary services billed to Medicare and Medicaid. Together with DaVita, Fresenius spent approximately $220 million on California ballot measures to block dialysis profit caps and staffing requirements.","verdict_tags":["231m_doj_medically_unnecessary_services","35pct_us_dialysis_market","davita_duopoly_70pct_combined","california_ballot_110m_opposition_spending","medicare_medicaid_billing_fraud"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Fresenius Medical Care employs approximately 120,000 people globally. California ballot measures that Fresenius opposed would have imposed minimum staffing requirements at dialysis centers.","flags":["california_staffing_proposition_opposition"],"sources":[]},"environmental":{"summary":"Dialysis is water-intensive — approximately 135 liters of highly purified water per session. No major environmental enforcement actions have been identified.","flags":["water_consumption_at_scale"],"sources":[]},"political":{"summary":"Fresenius and DaVita together spent approximately $111 million to defeat California's Proposition 8 (2018) and approximately $110 million to defeat Proposition 23 (2020). The combined spending of approximately $220 million across two California ballot campaigns is among the largest industry spending against a ballot measure in California history.","flags":["110m_california_prop_23_opposition","111m_california_prop_8_opposition","220m_combined_two_california_ballot_campaigns"],"sources":[]},"legal":{"summary":"February 2019: Fresenius Medical Care agreed to pay $231 million to resolve DOJ False Claims Act allegations covering medically unnecessary dialysis services — including unnecessary drugs, unnecessary lab tests, and unnecessary supplies billed to Medicare and Medicaid across facilities in more than 20 states. Separately, the GranuFlo/NaturaLyte product recall in 2012 covered cardiac deaths at dialysis facilities after Fresenius distributed an internal memo about cardiac risk only to Fresenius-owned facilities.","flags":["231m_unnecessary_services_settlement","20_plus_states_fraud_coverage","granuflo_naturlyte_cardiac_deaths_recall"],"sources":["https://www.justice.gov/opa/pr/fresenius-medical-care-pays-231-million-resolve-false-claims-act-allegations"]},"tax":{"summary":"Fresenius Medical Care is incorporated in Germany. The $231 million settlement may be partially tax-deductible.","flags":["german_corporate_tax_domicile","settlement_deductibility"],"sources":[]},"executives":{"summary":"Fresenius Medical Care has had multiple CEO transitions. No executives were personally charged in either the unnecessary services settlement or the GranuFlo matter.","flags":["no_executive_criminal_charges"],"sources":[]},"connections":{"summary":"Fresenius Medical Care and DaVita together control approximately 70% of US dialysis — an effective duopoly over a life-sustaining medical service. Both companies lobbied against the same California ballot measures simultaneously.","flags":["davita_parallel_conduct_fraud_lobbying_duopoly","geographic_monopoly_patient_captivity"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Whistleblowers in the $231 million case alleged that the unnecessary service billing was a corporate-level protocol designed to maximize Medicare reimbursement. The GranuFlo/NaturaLyte litigation alleged that Fresenius knew about cardiac risk signals before the recall and selectively distributed warning information only to its own facilities.","flags":["corporate_level_unnecessary_billing_protocol_alleged","granuflo_early_risk_signal_selective_distribution_alleged"],"sources":[]},"health_record":{"summary":"Dialysis is a life-sustaining treatment. Fresenius's billing of medically unnecessary services exposed patients to procedures they did not need. The GranuFlo recall: Fresenius internal documents showed awareness of elevated cardiac arrest rates before the recall was issued. An internal memo was distributed only to Fresenius-owned facilities — not to independent clinics using the same products.","flags":["unnecessary_drug_exposure_medicare_fraud","granuflo_internal_memo_selective_distribution_recall"],"sources":["https://www.fda.gov/medical-devices/medical-device-recalls/fresenius-medical-care-recalls-granuflo"]},"alternatives":{"cheaper":["Home dialysis — peritoneal dialysis or home hemodialysis — costs Medicare significantly less and is associated with better quality of life."],"healthier":["Home dialysis has documented quality of life advantages","Kidney transplantation — eliminates dialysis dependency entirely"],"diy":["If you are a dialysis patient: know you have the legal right to transfer to a different dialysis facility","Advocate for Medicare policy that encourages home dialysis as the default option"]},"timeline":[{"year":2012,"event":"GranuFlo/NaturaLyte recall: internal Fresenius memo about cardiac risk distributed only to Fresenius facilities, not independent clinics using same products","severity":"critical","source_url":""},{"year":2018,"event":"California Proposition 8 (dialysis profit cap) defeated; Fresenius and DaVita spend $111M in opposition","severity":"high","source_url":""},{"year":2019,"event":"$231M DOJ settlement for medically unnecessary services across 20+ states","severity":"critical","source_url":"https://www.justice.gov/opa/pr/fresenius-medical-care-pays-231-million-resolve-false-claims-act-allegations"},{"year":2020,"event":"California Proposition 23 (dialysis staffing requirements) defeated; industry spends ~$110M in opposition","severity":"high","source_url":""}],"community_impact":{"displacement":"Fresenius's geographic market position — approximately 35% of US dialysis — means that in many communities, Fresenius is the only practical dialysis option. Patients requiring three sessions per week cannot easily seek alternatives.","price_illusion":"Dialysis is covered almost universally by Medicare. But Medicare pays Fresenius approximately $250+ per session. The $231 million settlement established that some of those sessions included unnecessary drugs, tests, and supplies.","tax_math":"German company Fresenius receives approximately $7-10 billion annually from US Medicare funds. The $231 million settlement for false billing is partially tax-deductible. The $220 million spent defeating California ballot measures is a business expense reducing taxable income.","wealth_velocity":"Fresenius Medical Care is traded on the Frankfurt Stock Exchange with primarily German and international institutional shareholders. Revenue from Medicare's ESRD program — funded by American payroll taxes — flows to German shareholders."},"cost_absorption":{"who_benefited":[{"group":"Fresenius shareholders","how":"Revenue from medically unnecessary services billed to Medicare; $220M ballot measure spending preserved favorable California regulatory environment"}],"who_paid":[{"group":"Medicare / US taxpayers","how":"$231M+ in false billing for medically unnecessary drugs, tests, and supplies across 20+ states"},{"group":"200,000+ dialysis patients in Fresenius centers","how":"Subjected to unnecessary procedures; captive market with no practical alternative in most communities"}],"the_gap":"Fresenius controls 35% of US dialysis. Together with DaVita they control 70%. Dialysis patients cannot miss their treatment. They paid $231 million for billing Medicare for services patients did not need. They spent $220 million defeating two California ballot measures that would have added accountability. No executive was criminally charged. The duopoly is intact."}});
w('profiles_v5','stellantis',{"brand_name":"Stellantis","brand_slug":"stellantis","parent_company":"Stellantis N.V.","ultimate_parent":"Stellantis N.V.","overall_concern_level":"significant","profile_type":"database","generated_headline":"FIAT CHRYSLER PAID $305 MILLION IN CRIMINAL FINES FOR ITS OWN DIESEL DEFEAT DEVICE IN RAMS AND JEEP GRAND CHEROKEES — BEFORE IT MERGED INTO STELLANTIS","executive_summary":"Stellantis N.V. is the world's third-largest automaker, formed in January 2021 through the merger of Fiat Chrysler Automobiles (FCA) and the PSA Group. Before the merger, Fiat Chrysler Automobiles paid $305 million in criminal fines and $2.8 billion in civil settlements in 2019 for installing emissions defeat device software in approximately 100,000 Ram 1500 trucks and Jeep Grand Cherokees sold in the US between 2014 and 2016. Stellantis's CEO Carlos Tavares abruptly resigned in December 2024 amid declining sales and strategic disputes with the board.","verdict_tags":["fca_305m_criminal_defeat_device","2_8b_civil_settlement","100000_ram_jeep_grand_cherokee_us_affected","nox_defeat_device_pre_merger","tavares_abrupt_resignation_2024"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Stellantis employs approximately 300,000 people globally. The 2023 UAW strike targeted Stellantis, Ford, and General Motors simultaneously. Stellantis eventually reached a UAW agreement providing approximately 25% wage increases over four years.","flags":["2023_uaw_strike_all_three_detroit_targeted","25pct_wage_increase_settlement"],"sources":[]},"environmental":{"summary":"Fiat Chrysler's diesel defeat device covered approximately 100,000 Ram 1500 trucks and Jeep Grand Cherokees — emitting NOx at significantly elevated rates during real-world driving versus regulatory test cycles.","flags":["100000_us_defeat_device_vehicles"],"sources":[]},"political":{"summary":"The FCA settlement required a consent decree with ongoing compliance monitoring by EPA and the California Air Resources Board. Stellantis has lobbied extensively on fuel economy standards, EV incentive policies, and tariffs.","flags":["consent_decree_epa_carb_ongoing"],"sources":[]},"legal":{"summary":"January 2019: FCA agreed to pay $305 million in criminal fines to the DOJ for Clean Air Act violations — installing defeat device software in Ram 1500 trucks and Jeep Grand Cherokees. An FCA subsidiary pleaded guilty. Civil settlements totaling approximately $2.8 billion covered consumer compensation, EPA civil penalties, and state enforcement.","flags":["305m_criminal_fine_clean_air_act","fca_subsidiary_criminal_guilty_plea","2_8b_civil_settlement"],"sources":["https://www.justice.gov/opa/pr/fiat-chrysler-automobiles-nv-agree-pay-over-800-million-dodge-ram-1500-truck-and-jeep"]},"tax":{"summary":"Stellantis is incorporated in the Netherlands. Dutch holding company structures are used by major European multinationals for tax management.","flags":["netherlands_incorporation_european_merger"],"sources":[]},"executives":{"summary":"CEO Carlos Tavares resigned in December 2024 after board disputes over strategic direction as Stellantis's US market share declined significantly. No Stellantis or FCA executive was criminally charged in the defeat device case — the criminal guilty plea was at the subsidiary level.","flags":["tavares_abrupt_resignation_december_2024","no_executive_criminal_charges_defeat_device"],"sources":[]},"connections":{"summary":"Stellantis's defeat device scandal operated through the same basic mechanism as Volkswagen's. The FCA case emerged from the same regulatory environment that caught VW, as EPA and CARB expanded their real-world testing programs following the VW discovery.","flags":["same_mechanism_as_vw_post_vw_regulatory_environment"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Plaintiff attorneys alleged that FCA's defeat device was as deliberate as VW's — that the software was specifically engineered to detect the particular drive cycles used in US regulatory testing. FCA denied this characterization.","flags":["defeat_device_deliberate_intent_disputed"],"sources":[]},"health_record":{"summary":"NOx emissions from the approximately 100,000 affected Ram and Jeep vehicles exceeded regulatory limits during real-world driving. Communities near highways where these vehicles operated absorbed excess NOx without knowledge that the vehicles were non-compliant.","flags":["100000_vehicles_elevated_nox_real_world"],"sources":[]},"alternatives":{"cheaper":["Toyota Tacoma for trucks — no defeat device history","Honda CR-V, Toyota RAV4 for SUV equivalents to Jeep Grand Cherokee"],"healthier":["Electric vehicles from any manufacturer eliminate tailpipe NOx entirely"],"diy":["Check your Ram 1500 or Jeep Grand Cherokee 3.0L diesel VIN against the FCA settlement recall list"]},"timeline":[{"year":2014,"event":"FCA begins selling Ram 1500 and Jeep Grand Cherokee with 3.0L EcoDiesel engines containing defeat device software","severity":"critical","source_url":""},{"year":2017,"event":"EPA and CARB issue notice of violation to FCA following expanded real-world emissions testing post-VW","severity":"critical","source_url":""},{"year":2019,"event":"$305M criminal fine; FCA subsidiary pleads guilty; $2.8B civil settlement","severity":"critical","source_url":"https://www.justice.gov/opa/pr/fiat-chrysler-automobiles-nv-agree-pay-over-800-million-dodge-ram-1500-truck-and-jeep"},{"year":2021,"event":"January: Stellantis formed through FCA-PSA merger; Carlos Tavares becomes CEO","severity":"neutral","source_url":""},{"year":2023,"event":"UAW strikes all three Detroit automakers; Stellantis settles for 25% wage increases","severity":"high","source_url":""},{"year":2024,"event":"December: CEO Tavares abruptly resigns amid declining US market share","severity":"high","source_url":""}],"community_impact":{"displacement":"Communities near highways absorbed elevated NOx from approximately 100,000 non-compliant FCA diesel vehicles between 2014 and the recall.","price_illusion":"The Ram 1500 and Jeep Grand Cherokee EcoDiesel were marketed as combining performance with fuel efficiency and environmental responsibility. The emissions compliance existed only during regulatory testing.","tax_math":"The $305 million criminal fine and civil settlements generated deductions that reduced Stellantis's (then FCA's) taxable income.","wealth_velocity":"Stellantis is publicly traded with broad European and North American institutional ownership. The Agnelli family (through Exor NV) holds approximately 14% and is the largest single shareholder."},"cost_absorption":{"who_benefited":[{"group":"FCA shareholders (now Stellantis)","how":"Revenue from selling diesel vehicles without the cost of actual emissions compliance technology"}],"who_paid":[{"group":"Ram and Jeep Grand Cherokee EcoDiesel buyers","how":"Premium paid for diesel drivetrain with emissions compliance that only existed during tests"},{"group":"Communities near highway corridors","how":"Elevated NOx from approximately 100,000 non-compliant vehicles for three years before recall"}],"the_gap":"Fiat Chrysler installed defeat device software in Ram trucks and Jeep Grand Cherokees. The vehicles passed emissions tests. They emitted significantly more NOx on the road. FCA paid $305 million in criminal fines. An FCA subsidiary pleaded guilty. No individual executive was criminally charged. The company merged into Stellantis. The new name does not include the word Fiat or Chrysler."}});
w('profiles_v5','dollar-tree',{"brand_name":"Dollar Tree","brand_slug":"dollar-tree","parent_company":"Dollar Tree, Inc.","ultimate_parent":"Dollar Tree, Inc.","overall_concern_level":"significant","profile_type":"database","generated_headline":"DOLLAR TREE PAID THE LARGEST OSHA FINE IN US HISTORY — $41.6 MILLION — AND A FAMILY DOLLAR WAREHOUSE HAD LIVE RODENTS CONTAMINATING FOOD PRODUCTS FOR NEARLY A YEAR","executive_summary":"Dollar Tree, Inc. operates over 16,000 discount retail stores across the Dollar Tree and Family Dollar banners, serving approximately 8 million customers daily — disproportionately in lower-income communities. In March 2023, Dollar Tree agreed to pay $41.675 million to settle OSHA violations — the largest OSHA settlement in US history — covering unsafe working conditions at 769 stores across 41 states. In February 2022, the FDA forced Dollar Tree's Family Dollar subsidiary to recall products from its West Memphis, Arkansas distribution center after inspectors found live rodents, dead rodents, rodent droppings, rodent urine, and bird droppings contaminating products including food, dietary supplements, and medications. Over 400 consumer products were recalled.","verdict_tags":["41_6m_largest_osha_fine_us_history","769_stores_41_states_safety_violations","family_dollar_rodent_warehouse_fda_recall","400_products_recalled_food_medication","blocked_fire_exits_documented"],"concern_flags":{"labor":true,"environmental":false,"political":false,"tax":false,"health":true,"legal":true},"labor":{"summary":"Dollar Tree's OSHA settlement covered 769 stores — systematic worker safety failures. Workers faced merchandise stacked to block fire exits, unsafe storage, inadequate staffing requiring single employees to unload trucks without assistance, and insufficient training.","flags":["769_stores_systematic_not_isolated_violations","blocked_fire_exits_documented","osha_systemic_reform_required"],"sources":["https://www.osha.gov/news/newsreleases/national/03282023"]},"environmental":{"summary":"The Family Dollar warehouse rodent infestation contaminated food and medication distributed to Family Dollar stores across the southeastern United States before the FDA inspection.","flags":["contaminated_food_medication_distributed_before_recall"],"sources":[]},"political":{"summary":"Dollar Tree and Family Dollar operate in communities — often rural, often lower-income — where they are frequently the only accessible source of household goods, food staples, and over-the-counter medications.","flags":["essential_community_resource_enforcement_complexity","food_desert_community_dependency"],"sources":[]},"legal":{"summary":"March 2023: Dollar Tree agreed to pay $41.675 million — the largest OSHA settlement in US history — to resolve willful and repeated violations at 769 stores across 41 states and Washington DC. Separately, the Family Dollar West Memphis warehouse recall (February 2022) covered approximately 400 products contaminated by rodent infestation spanning approximately 12 months.","flags":["41_6m_largest_osha_settlement_history","769_stores_willful_repeated_violations","fda_family_dollar_warehouse_recall_400_products","12_months_estimated_infestation_period"],"sources":["https://www.osha.gov/news/newsreleases/national/03282023","https://www.fda.gov/safety/recalls-market-withdrawals-safety-alerts/family-dollar-stores-voluntarily-recalls-products-due-possible-rodent-infestation"]},"tax":{"summary":"Dollar Tree benefits from standard US retail tax provisions. The company's $8.5 billion acquisition of Family Dollar in 2015 generated significant goodwill. Family Dollar write-downs generated tax deductions.","flags":["family_dollar_8_5b_acquisition_goodwill"],"sources":[]},"executives":{"summary":"CEO Rick Dreiling took over in 2022. No executives were personally charged in connection with either the OSHA violations or the Family Dollar warehouse contamination. Dollar Tree announced a plan to spin off or sell Family Dollar — acknowledging the $8.5 billion acquisition as underperforming.","flags":["family_dollar_acquisition_underperformance_acknowledged","no_executive_charges"],"sources":[]},"connections":{"summary":"Dollar Tree and Dollar General together dominate the dollar store sector. Academic research has documented that dollar store expansion correlates with closure of traditional grocery stores — creating a dynamic where the lower-cost dollar store format replaces a broader selection retailer while providing a narrower, less nutritious food selection.","flags":["dollar_general_dollar_store_sector_dominance","grocery_store_closure_correlation_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"OSHA's characterization of violations as 'willful and repeated' implies that Dollar Tree was aware of the conditions and did not correct them. Workers at multiple stores have alleged through OSHA complaints and media reports that store managers were aware of safety violations but continued practices due to staffing constraints.","flags":["willful_repeated_classification_osha","manager_awareness_alleged"],"sources":["https://www.osha.gov/news/newsreleases/national/03282023"]},"health_record":{"summary":"The Family Dollar West Memphis warehouse infestation contaminated food products, dietary supplements, and medications — including over-the-counter drugs — distributed across the southeastern United States. The contamination period extended approximately 12 months before FDA inspection. OSHA's documented blocked fire exits at 769 stores represent direct safety hazards to workers.","flags":["food_medication_supplement_contamination_distributed","12_month_contamination_period_before_recall","fire_exit_blocking_worker_safety_hazard"],"sources":["https://www.fda.gov/safety/recalls-market-withdrawals-safety-alerts/family-dollar-stores-voluntarily-recalls-products-due-possible-rodent-infestation"]},"alternatives":{"cheaper":["Dollar General — different company, similar price points; also has documented OSHA issues","Walmart Neighborhood Market for food staples — where available in rural communities"],"healthier":["Local food banks and food pantries for food access in communities where dollar stores are primary grocery option"],"diy":["If you purchased Family Dollar products before February 2022 from southeastern US stores: check the FDA recall list","Report unsafe conditions at any Dollar Tree or Family Dollar store to OSHA at 1-800-321-OSHA"]},"timeline":[{"year":2021,"event":"Estimated beginning of rodent infestation at Family Dollar West Memphis, AR distribution center","severity":"critical","source_url":""},{"year":2022,"event":"February: FDA inspection finds rodent infestation; forces recall of approximately 400 products","severity":"critical","source_url":"https://www.fda.gov/safety/recalls-market-withdrawals-safety-alerts/family-dollar-stores-voluntarily-recalls-products-due-possible-rodent-infestation"},{"year":2023,"event":"March: $41.675M OSHA settlement — largest in OSHA history — for willful and repeated violations at 769 stores","severity":"critical","source_url":"https://www.osha.gov/news/newsreleases/national/03282023"},{"year":2024,"event":"Dollar Tree announces plan to spin off or sell Family Dollar","severity":"moderate","source_url":""}],"community_impact":{"displacement":"Family Dollar stores are concentrated in lower-income and rural communities where they often serve as the primary accessible grocery and pharmacy source. The communities most dependent on Family Dollar were simultaneously the least likely to have alternatives when its products were recalled.","price_illusion":"Dollar Tree's price point and Family Dollar's low-cost positioning present as consumer savings. The full price includes: worker safety hazards from blocked exits that OSHA found willful and repeated; food and medication contaminated by rodent infestation distributed to communities before detection.","tax_math":"Dollar Tree's $8.5 billion Family Dollar acquisition generated goodwill and subsequent write-downs that reduced taxable income. The $41.6 million OSHA settlement is tax-deductible as a business expense.","wealth_velocity":"Dollar Tree is publicly traded with institutional and retail shareholder ownership. Revenue from stores serving lower-income communities generates shareholder returns."},"cost_absorption":{"who_benefited":[{"group":"Dollar Tree shareholders","how":"Revenue from stores operating with documented safety violations that were willful and repeated; lower labor costs from understaffed stores"}],"who_paid":[{"group":"Workers at 769 stores with blocked fire exits","how":"Daily exposure to fire safety hazards; ergonomic and injury risk from unsafe merchandise storage"},{"group":"Consumers who purchased contaminated Family Dollar products","how":"Food, medications, and supplements contaminated by rodent infestation for approximately 12 months before detection"}],"the_gap":"Dollar Tree had blocked fire exits at 769 stores. OSHA called the violations willful and repeated. The fine was $41.6 million — the largest OSHA fine in US history. The same company's warehouse had rodents contaminating food and medication for approximately 12 months before the FDA found it. The communities buying that food and medication had the fewest alternatives. No executive was criminally charged."}});
w('profiles_v5','lyft',{"brand_name":"Lyft","brand_slug":"lyft","parent_company":"Lyft, Inc.","ultimate_parent":"Lyft, Inc.","overall_concern_level":"moderate","profile_type":"database","generated_headline":"LYFT SPENT $220 MILLION WITH UBER TO BLOCK DRIVER EMPLOYEE STATUS — THEN PUBLISHED A SAFETY REPORT ADMITTING 4,158 SEXUAL ASSAULTS IN TWO YEARS","executive_summary":"Lyft, Inc. is the second-largest US rideshare company. In 2020, Lyft and Uber together spent approximately $220 million to fund California's Proposition 22 — which exempted rideshare and delivery companies from AB5, a California law that would have required classifying gig workers as employees. Proposition 22 passed but was subsequently ruled unconstitutional by a California Superior Court judge in 2021. Lyft's 2019 safety report revealed that 4,158 sexual assault reports were filed against Lyft drivers in 2017 and 2018 combined. Academic research documents that Lyft drivers earn below minimum wage after expenses.","verdict_tags":["220m_prop_22_gig_worker_classification_blocking","prop_22_ruled_unconstitutional_appealing","4158_sexual_assaults_2017_2018","safety_report_pressure_required","driver_below_minimum_wage_after_expenses_documented"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Lyft classifies drivers as independent contractors — denying them minimum wage guarantees, overtime pay, health insurance, workers' compensation, and unemployment insurance. A 2018 MIT study found Lyft and Uber drivers earned a median of $3.37 per hour profit after expenses — below the federal minimum wage.","flags":["below_minimum_wage_after_expenses_mit_documented","no_workers_compensation_independent_contractor"],"sources":[]},"environmental":{"summary":"Rideshare vehicles add to urban congestion. Studies have documented that Lyft and Uber increase vehicle miles traveled by reducing transit ridership and adding deadhead miles.","flags":["congestion_increase_transit_reduction_documented"],"sources":[]},"political":{"summary":"Lyft and Uber's $220 million Proposition 22 campaign is the most expensive ballot measure campaign in California history. The California Superior Court judge who ruled Prop 22 unconstitutional in 2021 found it violated the California Constitution by limiting the legislature's authority over workers' compensation. The appeal is ongoing.","flags":["220m_most_expensive_california_ballot_measure","unconstitutional_ruling_superior_court_2021"],"sources":[]},"legal":{"summary":"Lyft's 2019 safety report disclosed 4,158 sexual assault reports filed in 2017 and 2018. Lyft settled a class action for $25 million in 2021 covering sexual assault claims. The company also faced a 2023 FTC settlement over sharing driver geolocation data with third parties without adequate disclosure.","flags":["4158_sexual_assaults_2017_2018_disclosed","25m_sexual_assault_class_action_settlement","ftc_geolocation_data_sharing_settlement"],"sources":["https://www.nytimes.com/2019/10/03/technology/lyft-safety-report-sexual-assaults.html"]},"tax":{"summary":"Lyft has generated significant accumulated losses since its founding, reducing or eliminating US corporate tax obligations for most of its operating history. Independent contractor classification means Lyft avoids employer-side payroll taxes on the labor its platform depends on.","flags":["accumulated_losses_minimal_corporate_tax","independent_contractor_payroll_tax_avoidance"],"sources":[]},"executives":{"summary":"CEO David Risher replaced co-founder Logan Green in April 2023. Co-founders Logan Green and John Zimmer led the company through the Prop 22 campaign, the safety report, and the 2019 IPO that valued Lyft at approximately $24 billion.","flags":["24b_ipo_without_profitability"],"sources":[]},"connections":{"summary":"Lyft's Prop 22 campaign was coordinated with Uber — the two primary competitors jointly funded the same ballot measure to block employee classification. This represents a documented instance of competitors working together to weaken labor protections for their shared workforce.","flags":["uber_lyft_competitor_coordination_against_workers"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Sexual assault plaintiffs have alleged that Lyft received complaints about specific drivers before subsequent assaults and did not deactivate those drivers in a timely manner.","flags":["prior_complaints_before_subsequent_assaults_alleged"],"sources":[]},"health_record":{"summary":"Lyft's 2019 safety report disclosed 4,158 sexual assault reports across 2017 and 2018 — incidents involving passengers assaulting drivers and drivers assaulting passengers. The report disclosed nine people murdered during Lyft rides in the same period.","flags":["4158_sexual_assaults_2017_2018","9_murders_2017_2018_disclosed"],"sources":["https://www.nytimes.com/2019/10/03/technology/lyft-safety-report-sexual-assaults.html"]},"alternatives":{"cheaper":["Public transit where available — genuinely lower cost, lower environmental impact, union-represented workers with benefits"],"healthier":["Worker-owned rideshare cooperatives where available"],"diy":["Calculate your true hourly earnings if you are a Lyft driver: vehicle depreciation, insurance costs, fuel, and maintenance must all be subtracted"]},"timeline":[{"year":2019,"event":"March: Lyft IPO at approximately $24B valuation. October: Lyft publishes safety report disclosing 4,158 sexual assaults in 2017-2018 and 9 murders.","severity":"critical","source_url":"https://www.nytimes.com/2019/10/03/technology/lyft-safety-report-sexual-assaults.html"},{"year":2020,"event":"November: Prop 22 passes with $220M in Lyft/Uber funding","severity":"critical","source_url":""},{"year":2021,"event":"California Superior Court rules Prop 22 unconstitutional; Lyft and Uber appeal. $25M class action settlement for sexual assault claims.","severity":"critical","source_url":""},{"year":2023,"event":"April: Co-founder Logan Green steps down as CEO; David Risher appointed","severity":"moderate","source_url":""}],"community_impact":{"displacement":"When COVID-19 eliminated rideshare demand overnight in March 2020, Lyft drivers had no unemployment safety net — because they were classified as independent contractors.","price_illusion":"Lyft rides appear affordable. Academic research establishes that drivers earn below minimum wage after vehicle costs. The apparent affordability is partially subsidized by transferring costs onto drivers who have no employment protections.","tax_math":"Independent contractor classification means Lyft does not pay employer-side payroll taxes on the labor its platform depends on. Drivers pay both employee and employer sides of FICA as self-employed individuals.","wealth_velocity":"Lyft's co-founders and early investors received significant returns through the 2019 IPO. Revenue generated by Lyft drivers' labor concentrates in San Francisco and in institutional shareholder portfolios."},"cost_absorption":{"who_benefited":[{"group":"Lyft founders and investors","how":"$24B IPO valuation on a company built on worker classification that avoids minimum wage, overtime, workers' compensation, and benefits"}],"who_paid":[{"group":"Lyft drivers","how":"Vehicle depreciation, fuel, insurance, and maintenance reduce earnings to below minimum wage per MIT research; no workers' compensation; no unemployment during demand drops"},{"group":"Sexual assault victims (4,158 reported 2017-2018)","how":"Assaults during Lyft rides; $25M class action settlement; safety report required advocacy pressure to publish"}],"the_gap":"Lyft drivers earn $3.37 per hour after expenses per MIT research. Lyft spent $220 million with Uber to make sure that doesn't have to change. Their safety report — which they published only after sustained advocacy pressure — showed 4,158 sexual assaults in two years. The measure they funded was ruled unconstitutional. They're appealing it. The founders took the company public at $24 billion."}});
w('profiles_v5','barclays',{"brand_name":"Barclays","brand_slug":"barclays","parent_company":"Barclays PLC","ultimate_parent":"Barclays PLC","overall_concern_level":"significant","profile_type":"database","generated_headline":"BARCLAYS PAID $361 MILLION FOR MANIPULATING HOW MUCH MONEY IT WAS RAISING DURING THE 2008 CRISIS — THEN PAID $2.4 BILLION FOR MORTGAGE SECURITIES FRAUD — THEN BECAME EUROPE'S LARGEST FOSSIL FUEL FINANCIER","executive_summary":"Barclays PLC is the UK's third-largest bank and one of the world's largest investment banks. Barclays paid $361 million to the DOJ in 2016 to resolve allegations that it manipulated the price of its own securities during a 2008 fundraising from Qatar and Abu Dhabi. Barclays paid $2 billion to the DOJ in 2016 for mortgage-backed securities fraud. The bank was the first major bank fined for LIBOR manipulation in 2012 — paying $290 million to US and UK regulators. Rainforest Action Network's Banking on Climate Chaos report has consistently ranked Barclays as the largest European financier of fossil fuel expansion globally, having provided approximately $167 billion in fossil fuel financing since the Paris Agreement.","verdict_tags":["361m_qatar_securities_manipulation","2b_mortgage_securities_fraud","290m_libor_first_major_bank_fined","167b_fossil_fuel_financing_since_paris","largest_european_fossil_fuel_financier_ran"],"concern_flags":{"labor":false,"environmental":true,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Barclays employs approximately 83,000 people globally. Multiple rounds of significant workforce reductions have occurred. No major documented systemic labor violations have been identified as a primary concern.","flags":[],"sources":[]},"environmental":{"summary":"Rainforest Action Network's annual Banking on Climate Chaos report has ranked Barclays as Europe's largest fossil fuel financier every year since the report's inception — providing approximately $167 billion in fossil fuel financing from 2016 through 2023. ShareAction and other investor advocacy organizations have consistently found Barclays's climate commitments inadequate relative to Paris Agreement targets.","flags":["167b_fossil_fuel_since_paris_2016_2023","largest_european_fossil_fuel_financier_annual"],"sources":["https://www.ran.org/bankingonclimatchaos2024/"]},"political":{"summary":"The Qatar fundraising case — in which Barclays avoided a UK government bailout during the 2008 financial crisis by raising capital from Qatar's sovereign wealth fund through arrangements prosecutors alleged involved improper payments — was investigated by the UK Serious Fraud Office. The SFO brought criminal charges against Barclays and four executives in 2017. The cases were dropped following judicial rulings. The US DOJ civil resolution remained.","flags":["sfo_criminal_charges_four_executives_dropped","uk_bailout_avoidance_qatar_fundraising_context"],"sources":[]},"legal":{"summary":"June 2012: Barclays became the first major bank fined for LIBOR manipulation — $290 million. June 2016: Barclays paid $100 million to 44 US states for LIBOR-related conduct. March 2022: Barclays agreed to pay $361 million to the DOJ for alleged improper payments to Qatari investors. August 2016: Barclays agreed to pay $2 billion to the DOJ for selling toxic mortgage-backed securities. Total US regulatory settlements exceed $2.5 billion.","flags":["290m_libor_first_major_bank","361m_qatar_improper_payments","2b_mortgage_securities","2_5b_total_us_settlements_decade"],"sources":["https://www.justice.gov/opa/pr/department-justice-announces-2-billion-resolution-barclays"]},"tax":{"summary":"In 2012, Barclays was forced to disclose two tax avoidance schemes after HMRC challenged them — paying approximately £500 million in backdated taxes and penalties.","flags":["500m_hmrc_backdated_taxes_penalties_2012"],"sources":[]},"executives":{"summary":"CEO Bob Diamond resigned in July 2012 following the LIBOR fine. Current CEO CS Venkatakrishnan leads Barclays. No Barclays executive was criminally convicted — the SFO's individual cases were dropped on procedural grounds.","flags":["diamond_resignation_bank_england_chancellor_pressure","no_executive_conviction_despite_sfo_charges"],"sources":[]},"connections":{"summary":"Barclays' LIBOR manipulation was part of an industry-wide scandal that implicated Deutsche Bank, UBS, Citigroup, JPMorgan Chase, and others — collectively paying over $9 billion in LIBOR-related fines globally. Barclays was first and its settlement established the template for others.","flags":["libor_industry_wide_pattern_first_settled"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The SFO's criminal charges alleged that the Qatari payments were structured as 'advisory service agreements' for services never actually rendered. Barclays has denied the characterization.","flags":["qatar_advisory_agreements_for_unrendered_services_alleged"],"sources":[]},"health_record":{"summary":"Barclays's fossil fuel financing — $167 billion since the Paris Agreement — provides the capital for energy infrastructure that climate science documents will contribute to global warming beyond the 1.5°C target. The health consequences of climate change are documented by WHO and IPCC as among the most significant global health threats.","flags":["167b_fossil_fuel_financing_climate_health_impact"],"sources":[]},"alternatives":{"cheaper":["UK building societies and credit unions — member-owned, not-for-profit; no LIBOR manipulation, no fossil fuel financing at Barclays's scale"],"healthier":["Triodos Bank — certified B Corp; publishes full loan book; no fossil fuel financing by policy"],"diy":["Check Barclays's current fossil fuel financing policies at shareaction.org","Move your account to a bank with documented fossil fuel exclusion policies"]},"timeline":[{"year":2008,"event":"Barclays raises emergency capital from Qatar and Abu Dhabi; avoids UK government bailout; payments later alleged as improper","severity":"critical","source_url":""},{"year":2012,"event":"June: $290M LIBOR settlement — first major bank fined; CEO Bob Diamond resigns. February: HMRC forces disclosure of two Barclays tax avoidance schemes; ~£500M in backdated taxes paid.","severity":"critical","source_url":""},{"year":2016,"event":"$2B DOJ settlement for mortgage-backed securities fraud. $100M additional LIBOR settlement with 44 US states.","severity":"critical","source_url":""},{"year":2017,"event":"UK SFO brings criminal charges against Barclays and four executives over 2008 Qatar fundraising","severity":"critical","source_url":""},{"year":2020,"event":"SFO criminal case against Barclays dropped following Court of Appeal ruling on SFO procedures","severity":"high","source_url":""},{"year":2022,"event":"$361M DOJ civil resolution for Qatar improper payments","severity":"high","source_url":""},{"year":2024,"event":"Barclays ranked largest European fossil fuel financier for eighth consecutive year","severity":"high","source_url":""}],"community_impact":{"displacement":"Communities near fossil fuel projects financed by Barclays's $167 billion in energy lending absorb environmental and health impacts from extraction and combustion.","price_illusion":"Barclays presents its fossil fuel financing as prudent capital allocation. Climate science published by the IEA and IPCC documents that investments in new fossil fuel infrastructure are incompatible with limiting warming to 1.5°C.","tax_math":"The HMRC tax avoidance schemes — for which Barclays paid £500 million in backdated taxes — involved structured financial transactions designed to generate artificial tax losses. The LIBOR and mortgage securities settlements have generated US tax deductions.","wealth_velocity":"Barclays is publicly traded on the London Stock Exchange. Revenue from fossil fuel financing transactions — which fund infrastructure contributing to climate change — flows to Barclays shareholders."},"cost_absorption":{"who_benefited":[{"group":"Barclays shareholders","how":"Avoided UK government bailout through Qatar capital; LIBOR manipulation revenue; mortgage securities fee income; fossil fuel financing fees"}],"who_paid":[{"group":"LIBOR-linked contract holders globally","how":"Overcharged on interest rates by manipulated benchmark affecting trillions in financial contracts"},{"group":"Communities absorbing climate impacts","how":"Heat, flooding, air quality, displacement from climate change that Barclays-financed fossil fuel infrastructure contributes to"}],"the_gap":"Barclays was the first major bank fined for LIBOR manipulation. It paid $2 billion for mortgage fraud. It paid $361 million for what the DOJ called improper payments to the investors who funded its 2008 survival. The UK's SFO charged it with fraud and then dropped the case on a procedural ruling. It has provided $167 billion in fossil fuel financing since the Paris Agreement. It is Europe's largest fossil fuel financier. Its net zero target is 2050."}});
w('profiles_v5','ab-inbev',{"brand_name":"AB InBev","brand_slug":"ab-inbev","parent_company":"Anheuser-Busch InBev SA/NV","ultimate_parent":"Anheuser-Busch InBev SA/NV","overall_concern_level":"significant","profile_type":"database","generated_headline":"AB INBEV CONTROLS 25% OF ALL BEER SOLD ON EARTH AND PAID $100 MILLION FOR BRIBING OFFICIALS IN INDIA — IT ALSO WATERED DOWN BUDWEISER AND ADMITTED IT","executive_summary":"Anheuser-Busch InBev SA/NV is the world's largest beer company, controlling approximately 25% of global beer volume across over 500 brands including Budweiser, Bud Light, Corona, and Stella Artois. AB InBev paid $100 million in 2016 to the SEC and DOJ to resolve FCPA violations — its Indian subsidiary had bribed government officials to obtain regulatory approvals. In 2015, AB InBev paid $20 million to settle a class action alleging it had watered down Budweiser, Bud Light, and other beers — reducing their alcohol content below what was labeled. The company's 3G Capital-driven zero-based budgeting model has generated documented product quality concerns and workforce destruction across its acquired brands.","verdict_tags":["100m_fcpa_india_bribery","20m_watered_down_budweiser_settlement","25pct_global_beer_market","3g_capital_zero_based_budgeting","craft_beer_acquisition_independence_concerns"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"AB InBev's 3G Capital-driven management model applies zero-based budgeting resulting in systematic workforce reductions across acquired companies. When AB InBev acquired SABMiller in 2016 for $107 billion, thousands of jobs were eliminated through ZBB cost-cutting.","flags":["3g_capital_zero_based_budgeting_workforce_destruction","sabmiller_acquisition_job_cuts"],"sources":[]},"environmental":{"summary":"Beer production is water-intensive — AB InBev has committed to water stewardship targets given that water scarcity directly threatens its production. The company is among the world's largest commercial water users.","flags":["largest_commercial_water_users","water_scarcity_production_risk"],"sources":[]},"political":{"summary":"AB InBev's FCPA violations in India involved its subsidiary paying approximately $2.7 million in bribes to state government officials to obtain regulatory approvals. The company lobbies against alcohol advertising restrictions and minimum pricing legislation globally.","flags":["india_government_official_bribes_regulatory_approvals","alcohol_advertising_restriction_opposition"],"sources":[]},"legal":{"summary":"2016: AB InBev paid $100 million to the SEC and DOJ — $45 million criminal penalty plus $55 million civil — to resolve FCPA violations covering bribery of Indian government officials by its subsidiary. 2015: $20 million class action settlement alleging AB InBev watered down Budweiser, Bud Light, and other beers — reducing alcohol content below labeled levels.","flags":["100m_fcpa_india_45m_criminal_55m_civil","20m_watered_down_budweiser_class_action","alcohol_content_below_labeled_levels"],"sources":[]},"tax":{"summary":"AB InBev is incorporated in Belgium — benefiting from Belgian tax arrangements. The company's acquisition of SABMiller created complex international tax structures across over 50 markets. 3G Capital's management model includes aggressive cost management that extends to tax optimization across jurisdictions.","flags":["belgium_incorporation_tax_arrangements","sabmiller_complex_international_tax"],"sources":[]},"executives":{"summary":"CEO Michel Doukeris leads AB InBev. Jorge Paulo Lemann (3G Capital founder) and his partners created the ZBB model defining AB InBev's management. No AB InBev executive was criminally charged in the India FCPA settlement.","flags":["3g_capital_lemann_investment_philosophy","no_executive_criminal_charges_india_fcpa"],"sources":[]},"connections":{"summary":"AB InBev's acquisition strategy — buying independent craft breweries including Goose Island, Blue Point, 10 Barrel Brewing, and others — has generated consumer backlash from craft beer communities. AB InBev has been accused of using these acquisitions to compete with genuinely independent craft brewers while obscuring its ownership.","flags":["craft_brewery_acquisition_independence_deception","goose_island_10_barrel_ownership_obscured"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The watered-down beer class action alleged that AB InBev used a flow meter in its production process that systematically reduced the alcohol content of finished products below labeled levels — and that this was a cost-reduction practice rather than a production accident. AB InBev denied intentional watering but settled for $20 million.","flags":["flow_meter_systematic_alcohol_reduction_alleged"],"sources":[]},"health_record":{"summary":"AB InBev controls 25% of global beer — its marketing decisions shape alcohol consumption patterns at population scale. The watered-down beer settlement established that products were sold with inaccurate alcohol content labeling — affecting consumers who made decisions based on labeled alcohol levels.","flags":["25pct_global_beer_consumption_marketing_influence","inaccurate_alcohol_labeling_settled"],"sources":[]},"alternatives":{"cheaper":["Genuinely independent craft breweries — Brewers Association maintains a list of verified independent craft brewers","Local microbreweries and brewpubs — profits stay in community"],"healthier":["Reduced alcohol consumption — no brand switching addresses the underlying alcohol health question"],"diy":["The Brewers Association's independent craft brewer seal (independentcraft.com) identifies genuinely independent breweries","AB InBev-owned craft brands include: Goose Island, Blue Point, 10 Barrel, Elysian, Golden Road, Karbach, Wicked Weed"]},"timeline":[{"year":2008,"event":"InBev acquires Anheuser-Busch for $52B; creates world's largest beer company","severity":"neutral","source_url":""},{"year":2015,"event":"$20M class action settlement for watering down Budweiser, Bud Light, and other beers below labeled alcohol content","severity":"high","source_url":""},{"year":2016,"event":"$100M FCPA settlement for India bribery. $107B SABMiller acquisition completed.","severity":"critical","source_url":""}],"community_impact":{"displacement":"AB InBev's ZBB model applies global cost standards to local operations, eliminating thousands of jobs across acquired brands.","price_illusion":"AB InBev's watered-down beer settlement established that Budweiser and Bud Light were sold with inaccurate alcohol content labeling. AB InBev's 'craft' acquisitions present as independent local breweries while routing revenue to a Belgian holding company.","tax_math":"AB InBev's Belgian incorporation and complex international structure manages global tax obligations across 50+ markets. The $100 million FCPA settlement is tax-deductible.","wealth_velocity":"AB InBev is publicly traded on Euronext Brussels. 3G Capital partners — Jorge Paulo Lemann, Marcel Telles, and Carlos Sicupira — hold significant stakes and have become among the wealthiest people in the world through the beer consolidation strategy."},"cost_absorption":{"who_benefited":[{"group":"3G Capital partners and AB InBev shareholders","how":"25% global beer market share through aggressive acquisition; ZBB cost model extracting margins from every acquired operation; India market access obtained through bribery"}],"who_paid":[{"group":"Consumers who bought watered-down Budweiser","how":"Paid for labeled alcohol content they did not receive; $20M settlement"}],"the_gap":"AB InBev controls 25% of all beer sold on Earth. It paid $100 million for bribing Indian government officials. It paid $20 million for watering down Budweiser below its labeled alcohol content. It owns Goose Island, Blue Point, 10 Barrel, and dozens of other 'craft' breweries that most consumers don't know are AB InBev. Jorge Paulo Lemann is one of the wealthiest people in the world. The beer is cheaper now."}});
